    @php
        $primary = data_get($diaspora->theme, 'primary', '#167B5A');
        $supportedLocales = is_string($diaspora->supported_locales) ? (json_decode($diaspora->supported_locales, true) ?: ['ru']) : (array)$diaspora->supported_locales;
        $nativeLocale = collect($supportedLocales)->first(fn($locale) => $locale !== 'ru') ?: $diaspora->default_locale;
        $localized = function ($value, $locale = 'ru') {
            $data = is_string($value) ? json_decode($value, true) : (array)$value;
            return $data[$locale] ?? $data['ru'] ?? '';
        };
        $statusClass = fn($status) => match($status) {
            'active','published','verified','resolved' => 'success',
            'moderation','new','in_progress','reviewed' => 'warning',
            'blocked','rejected','hidden','suspended' => 'danger',
            default => 'secondary'
        };
    @endphp
